fn winsorize(x, lower_pct, upper_pct):
  lower = quantile(x, lower_pct)
  upper = quantile(x, upper_pct)
  clip(x, lower, upper)

fn robust_zscore(x):
  median_val = median(x)
  mad = median(abs(x - median_val))
  (x - median_val) / (1.4826 * mad + 0.0001)

